package com.xworkz.variables.external;

class StaticVariableDemo {

    // Static variables
    static String name = "Thejas";
    static int age = 21;

    public static void main(String[] args) {
        System.out.println("Name: " + name);
        System.out.println("Age : " + age);
        String name = "Thejas";
        name="Sajay";
    }


}

